import React from "react";
import "./Login.css";
import TextField from "@material-ui/core/TextField";
import Button from "@material-ui/core/Button";
import CircularProgress from "@material-ui/core/CircularProgress";
import Container from "@material-ui/core/Container";
import Grid from "@material-ui/core/Grid";
import axios from "axios";
import Data from "./Data";

class Login extends React.Component {
  state = {
    isLoading: false,
    lastLoginFailed: false,
  };

  getClockState() {
    this.setState({ isLoading: true });
    if (this.state.ip !== "") {
      axios
        .get("http://" + Data.ip, { timeout: 1000 })
        .then((result) => {
          Data.data = result.data;
          this.setState({
            isLoading: false,
          });
          if (Data.data.NAME === "WallClock") {
            this.props.history.push({
              pathname: "/home",
            });
          }
        })
        .catch((error) =>
          this.setState({
            isLoading: false,
            lastLoginFailed: true,
          })
        );
    } else {
      this.setState({ 
        isLoading: false, 
        lastLoginFailed: true 
      });
    }
  }

  handleChange = (e) => {
    this.setState({ ip: e.target.value });
  };

  checkIP = (e) => {
    this.getClockState();
  };

  keyPress = (e) => {
    if (e.key === "Enter") {
      this.checkIP();
    }
  };

  render() {
    return (
      <div className="Login">
        <Container maxWidth="xs">
          <Grid container spacing={2}>
            <Grid item xs={12}>
              test
              <TextField
                id="outlined-basic"
                label="IP Address"
                variant="outlined"
                onChange={this.handleChange}
                onKeyDown={this.keyPress}
                value={Data.ip}
                fullWidth={true}
              />
            </Grid>
            <Grid item xs={12}>
              {!this.state.isLoading && (
                <Button
                  size="large"
                  variant="contained"
                  color="primary"
                  onClick={this.checkIP}
                  fullWidth={true}
                >
                  Login
                </Button>
              )}
            </Grid>
            <Grid item xs={12}>
              {this.state.isLoading && <CircularProgress />}
            </Grid>
            <Grid item xs={12}>
              {this.state.lastLoginFailed && !this.state.isLoading && (
                <p id="error-msg">Last Login was not successful</p>
              )}
            </Grid>
          </Grid>
        </Container>
      </div>
    );
  }
}

export default Login;
